An  that detects and processes Old School
RuneScape (revision 317) client connections on a .


Register this handler so a single port can serve OSRS game clients alongside
HTTP, WebSocket, and other SocketJack protocols.



var server = new MutableTcpServer(43594, "GameServer");
server.RegisterProtocol(new OldschoolRunescape());
server.Listen();

A convenience wrapper that creates a  pre-configured
with the  protocol handler.


var server = new OldschoolServer(43594);
server.Protocol.PlayerAuthenticated += (conn, session) => {
    Console.WriteLine($"{session.Credentials.Username} logged in.");
};
server.Listen();

remarks.code:
var metadata = TorrentMetadata.FromFile("myfile.zip", new List<string> { "localhost:6969" });
var client = new TorrentClient(metadata, listenPort: 6881, downloadPath: "./downloads");
client.Seed("myfile.zip");
await client.StartAsync();

var server = new MutableTcpServer(8080, "MultiServer");
var client = new TorrentClient(metadata, downloadPath: "./downloads");
client.Register(server);
client.Seed("myfile.zip");
server.Listen();
await client.StartAsync();

example.code:
var server = new MutableTcpServer(8080, "MultiServer");
var metadata = TorrentMetadata.FromFile("patch.zip", new List<string> { "localhost:8080" });
var client = new TorrentClient(metadata, downloadPath: "./downloads");
client.Register(server);
client.Seed("patch.zip");
server.Listen();
await client.StartAsync();

member.summary:
Sends an object to the specified connection, routing through whichever
server is active (standalone  or registered
).

remarks.code:
var tracker = new TorrentTracker(port: 6969);
tracker.Start();
tracker.RegisterTorrent(metadata, category: "software");

var server = new MutableTcpServer(8080, "MultiServer");
var tracker = new TorrentTracker(server);
tracker.RegisterTorrent(metadata, category: "software");
server.Listen();
